package main

import (
    "errors"
    "os"
    "os/exec"
    "path/filepath"
    "strings"
)

// Compliant: Use absolute paths for critical commands
func compressFile(filename string) error {
    // Use absolute path to ensure we run the intended command
    cmd := exec.Command("/bin/tar", "-czf", filename+".tar.gz", filename)
    return cmd.Run()
}

// Compliant: Validate command against whitelist
var allowedCommands = map[string]string{
    "git":  "/usr/bin/git",
    "node": "/usr/bin/node",
    "npm": "/usr/bin/npm",
}

func runValidatedCommand(command string, args ...string) error {
    cmdPath, exists := allowedCommands[command]
    if !exists {
        return errors.New("command not allowed")
    }

    // Verify the executable exists and is executable
    if _, err := os.Stat(cmdPath); err != nil {
        return err
    }

    cmd := exec.Command(cmdPath, args...)
    return cmd.Run()
}

// Compliant: Use Go's built-in functions instead of external commands
func deleteDirectory(path string) error {
    // Use Go's built-in file operations instead of external rm
    return os.RemoveAll(path)
}

// Compliant: Validate found executables
func findAndExecuteSecure(cmdName string) error {
    cmdPath, err := exec.LookPath(cmdName)
    if err != nil {
        return err
    }

    // Validate the executable path
    if !isValidExecutablePath(cmdPath) {
        return errors.New("executable path not trusted")
    }

    cmd := exec.Command(cmdPath)
    return cmd.Run()
}

func isValidExecutablePath(path string) bool {
    // Define trusted directories
    trustedDirs := []string{"/usr/bin", "/bin", "/usr/local/bin"}

    absPath, err := filepath.Abs(path)
    if err != nil {
        return false
    }

    for _, dir := range trustedDirs {
        if strings.HasPrefix(absPath, dir) {
            return true
        }
    }
    return false
}
